import React, { useState, useEffect } from 'react';
import { View, Text, Button, FlatList, StyleSheet, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as Crypto from 'expo-crypto';

const STORAGE_KEY = '@offline_tokens';
const TOKEN_EXPIRY_HOURS = 24;

const OfflineTokenGenerator = () => {
  const [tokens, setTokens] = useState([]);
  const [isOnline, setIsOnline] = useState(true);

  useEffect(() => {
    loadTokens();
  }, []);

  const loadTokens = async () => {
    try {
      const storedTokens = await AsyncStorage.getItem(STORAGE_KEY);
      if (storedTokens) {
        const parsedTokens = JSON.parse(storedTokens);
        const validTokens = parsedTokens.filter(token => !isTokenExpired(token));
        setTokens(validTokens);
        await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(validTokens));
      }
    } catch (error) {
      console.error('Error loading tokens:', error);
    }
  };

  const generateSecureToken = async () => {
    try {
      const randomBytes = await Crypto.getRandomBytesAsync(32);
      const tokenString = Array.from(randomBytes)
        .map(byte => byte.toString(16).padStart(2, '0'))
        .join('');
      
      const timestamp = Date.now();
      const deviceId = await getDeviceIdentifier();
      
      const tokenData = `${tokenString}.${timestamp}.${deviceId}`;
      const signature = await generateHMAC(tokenData);
      
      return `${tokenData}.${signature}`;
    } catch (error) {
      console.error('Error generating token:', error);
      throw error;
    }
  };

  const getDeviceIdentifier = async () => {
    try {
      let deviceId = await AsyncStorage.getItem('@device_id');
      if (!deviceId) {
        const randomBytes = await Crypto.getRandomBytesAsync(16);
        deviceId = Array.from(randomBytes)
          .map(byte => byte.toString(16).padStart(2, '0'))
          .join('');
        await AsyncStorage.setItem('@device_id', deviceId);
      }
      return deviceId;
    } catch (error) {
      console.error('Error getting device identifier:', error);
      return 'unknown';
    }
  };

  const generateHMAC = async (data) => {
    try {
      let secretKey = await AsyncStorage.getItem('@hmac_secret');
      if (!secretKey) {
        const randomBytes = await Crypto.getRandomBytesAsync(32);
        secretKey = Array.from(randomBytes)
          .map(byte => byte.toString(16).padStart(2, '0'))
          .join('');
        await AsyncStorage.setItem('@hmac_secret', secretKey);
      }
      
      const digest = await Crypto.digestStringAsync(
        Crypto.CryptoDigestAlgorithm.SHA256,
        data + secretKey
      );
      
      return digest.substring(0, 16);
    } catch (error) {
      console.error('Error generating HMAC:', error);
      return '';
    }
  };

  const verifyToken = async (token) => {
    try {
      const parts = token.split('.');
      if (parts.length !== 4) return false;
      
      const [tokenString, timestamp, deviceId, signature] = parts;
      const tokenData = `${tokenString}.${timestamp}.${deviceId}`;
      const expectedSignature = await generateHMAC(tokenData);
      
      return signature === expectedSignature;
    } catch (error) {
      console.error('Error verifying token:', error);
      return false;
    }
  };

  const isTokenExpired = (token) => {
    try {
      const parts = token.token.split('.');
      if (parts.length < 2) return true;
      
      const timestamp = parseInt(parts[1], 10);
      const expiryTime = timestamp + (TOKEN_EXPIRY_HOURS * 60 * 60 * 1000);
      
      return Date.now() > expiryTime;
    } catch (error) {
      return true;
    }
  };

  const handleGenerateToken = async () => {
    try {
      const newToken = await generateSecureToken();
      const tokenObject = {
        id: await Crypto.digestStringAsync(
          Crypto.CryptoDigestAlgorithm.SHA256,
          newToken + Date.now()
        ),
        token: newToken,
        createdAt: new Date().toISOString(),
        actions: []
      };

      const updatedTokens = [...tokens, tokenObject];
      setTokens(updatedTokens);
      await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(updatedTokens));
      
      Alert.alert('Success', 'Secure token generated successfully');
    } catch (error) {
      Alert.alert('Error', 'Failed to generate token');
      console.error('Token generation error:', error);
    }
  };

  const handleTrackAction = async (tokenId, action) => {
    try {
      const updatedTokens = tokens.map(token => {
        if (token.id === tokenId) {
          const actionEntry = {
            id: Date.now().toString(),
            type: action,
            timestamp: new Date().toISOString()
          };
          return {
            ...token,
            actions: [...token.actions, actionEntry]
          };
        }
        return token;
      });

      setTokens(updatedTokens);
      await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(updatedTokens));
    } catch (error) {
      console.error('Error tracking action:', error);
    }
  };

  const handleClearTokens = async () => {
    try {
      setTokens([]);
      await AsyncStorage.removeItem(STORAGE_KEY);
      Alert.alert('Success', 'All tokens cleared');
    } catch (error) {
      Alert.alert('Error', 'Failed to clear tokens');
    }
  };

  const handleValidateToken = async (token) => {
    const isValid = await verifyToken(token.token);
    const isExpired = isTokenExpired(token);
    
    Alert.alert(
      'Token Validation',
      `Valid: ${isValid}\nExpired: ${isExpired}\nActions: ${token.actions.length}`
    );
  };

  const renderToken = ({ item }) => (
    <View style={styles.tokenCard}>
      <Text style={styles.tokenText} numberOfLines={1}>
        Token: {item.token.substring(0, 20)}...
      </Text>
      <Text style={styles.dateText}>Created: {new Date(item.createdAt).toLocaleString()}</Text>
      <Text style={styles.actionsText}>Actions tracked: {item.actions.length}</Text>
      <View style={styles.buttonRow}>
        <Button
          title="Track Action"
          onPress={() => handleTrackAction(item.id, 'user_action')}
        />
        <Button
          title="Validate"
          onPress={() => handleValidateToken(item)}
        />
      </View>
    </View>
  );

  return (
    <View style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.title}>Offline Token Manager</Text>
        <Text style={styles.status}>
          Status: {isOnline ? '🟢 Online' : '🔴 Offline'}
        </Text>
      </View>

      <View style={styles.controls}>
        <Button
          title="Generate Secure Token"
          onPress={handleGenerateToken}
        />
        <View style={styles.spacer} />
        <Button
          title="Clear All Tokens"
          onPress={handleClearTokens}
          color="#ff6b6b"
        />
      </View>

      <Text style={styles.sectionTitle}>Active Tokens ({tokens.length})</Text>
      
      <FlatList
        data={tokens}
        renderItem={renderToken}
        keyExtractor={item => item.id}
        style={styles.list}
        ListEmptyComponent={
          <Text style={styles.emptyText}>No tokens generated yet</Text>
        }
      />
    </View>
  );
};

